import { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import {
    LayoutDashboard,
    LogOut,
    User,
    ChevronDown,
    Menu,
    X,
    Settings,
    Shield
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

/**
 * Sidebar - Navegación lateral principal
 */
export default function Sidebar() {
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isProfileOpen, setIsProfileOpen] = useState(false);
    const location = useLocation();
    const navigate = useNavigate();
    const { user, logout } = useAuth();

    const navLinks = [
        { name: 'Dashboard', path: '/', icon: LayoutDashboard },
        { name: 'Firmas', path: '/signatures', icon: Settings },
        { name: 'Configuración', path: '/settings', icon: Settings },

    ];

    const isActive = (path) => {
        if (path === '/') return location.pathname === '/';
        return location.pathname.startsWith(path);
    };

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const NavItem = ({ link, mobile = false }) => {
        const active = isActive(link.path);
        const Icon = link.icon;

        return (
            <Link
                to={link.path}
                onClick={() => mobile && setIsMobileMenuOpen(false)}
                className={`
                    flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all duration-200 group
                    ${active
                        ? 'bg-[var(--color-primary)] text-white shadow-md shadow-[var(--color-primary)]/20'
                        : 'text-[var(--color-text-secondary)] hover:bg-[var(--color-bg-tertiary)] hover:text-[var(--color-text-primary)]'
                    }
                `}
            >
                <Icon className={`w-5 h-5 ${active ? 'text-white' : 'text-[var(--color-text-muted)] group-hover:text-[var(--color-text-primary)]'} transition-colors`} />
                <span className="font-medium text-sm">{link.name}</span>
            </Link>
        );
    };

    return (
        <>
            {/* Mobile Header Overlay */}
            <div className="lg:hidden fixed top-0 left-0 right-0 h-16 bg-[var(--color-bg-secondary)] border-b border-[var(--color-border)] flex items-center justify-between px-4 z-50">
                <div className="flex items-center gap-2 font-semibold text-[var(--color-text-primary)]">
                    <Shield className="w-6 h-6 text-[var(--color-primary)]" />
                    <span>HMR System</span>
                </div>
                <button
                    onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                    className="p-2 text-[var(--color-text-secondary)] hover:bg-[var(--color-bg-tertiary)] rounded-lg"
                >
                    {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
                </button>
            </div>

            {/* Sidebar Container */}
            <aside className={`
                fixed inset-y-0 left-0 z-40 w-64 bg-[var(--color-bg-secondary)] border-r border-[var(--color-border)] flex flex-col transition-transform duration-300 lg:translate-x-0 lg:static lg:h-screen
                ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
            `}>
                {/* Logo Header */}
                <div className="h-16 flex items-center px-6 border-b border-[var(--color-border)]">
                    <Link to="/" className="flex items-center gap-2.5 font-bold text-xl tracking-tight text-[var(--color-text-primary)]">
                        <div className="p-1.5 bg-[var(--color-primary)]/10 rounded-lg">
                            <Shield className="w-6 h-6 text-[var(--color-primary)]" />
                        </div>
                        <span>HMR<span className="text-[var(--color-primary)]"> System</span></span>
                    </Link>
                </div>

                {/* Navigation Links */}
                <div className="flex-1 overflow-y-auto py-6 px-4 space-y-1 scrollbar-hide">
                    <div className="text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider mb-4 px-2">
                        Menu Principal
                    </div>
                    {navLinks.map((link) => (
                        <NavItem key={link.path} link={link} />
                    ))}
                </div>
            </aside>

            {/* Mobile Overlay Backdrop */}
            {isMobileMenuOpen && (
                <div
                    className="fixed inset-0 bg-black/50 z-30 lg:hidden backdrop-blur-sm"
                    onClick={() => setIsMobileMenuOpen(false)}
                />
            )}
        </>
    );
}

import { createContext, useContext, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

/**
 * AuthContext - Contexto de autenticación global (Mock for Frontend only)
 */

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState(null);

    // Verificar sesión al cargar
    useEffect(() => {
        const token = localStorage.getItem('token');
        const savedUser = localStorage.getItem('user');

        if (token && savedUser) {
            try {
                setUser(JSON.parse(savedUser));
            } catch {
                localStorage.removeItem('token');
                localStorage.removeItem('user');
            }
        }
        setIsLoading(false);
    }, []);

    /**
     * Iniciar sesión (Mock)
     */
    const login = async (email, password) => {
        setError(null);
        setIsLoading(true);

        try {
            // Fake delay
            await new Promise((resolve) => setTimeout(resolve, 800));

            // Basic mock validation
            if (!email || !password) {
                throw new Error('Credenciales inválidas');
            }

            const mockToken = 'mock-jwt-token-12345';
            localStorage.setItem('token', mockToken);

            const userData = {
                email: email,
                full_name: 'Admin HMR'
            };
            localStorage.setItem('user', JSON.stringify(userData));
            setUser(userData);

            return { success: true };
        } catch (err) {
            const message = err.message || 'Error al iniciar sesión';
            setError(message);
            return { success: false, error: message };
        } finally {
            setIsLoading(false);
        }
    };

    /**
     * Registrar nuevo usuario (Mock)
     */
    const register = async (fullName, email, password) => {
        setError(null);
        setIsLoading(true);

        try {
            await new Promise((resolve) => setTimeout(resolve, 800));
            // Después de registrar, hacer login automático
            return await login(email, password);
        } catch (err) {
            const message = err.message || 'Error al registrar usuario';
            setError(message);
            return { success: false, error: message };
        } finally {
            setIsLoading(false);
        }
    };

    /**
     * Cerrar sesión
     */
    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        setUser(null);
    };

    const value = {
        user,
        isLoading,
        isAuthenticated: !!user,
        error,
        login,
        register,
        logout,
        clearError: () => setError(null),
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

/**
 * Hook para usar el contexto de autenticación
 */
export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth debe usarse dentro de un AuthProvider');
    }
    return context;
}

export default AuthContext;
